import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{n as i,r as a,t as o}from"./chunks/vm-arguments.BmU0TYdw.js";const s=JSON.parse(`{"title":"Запуск игры","description":"Узнайте, как использовать различные профили запуска для запуска и отладки ваших модов в реальной игровой среде.","frontmatter":{"title":"Запуск игры","description":"Узнайте, как использовать различные профили запуска для запуска и отладки ваших модов в реальной игровой среде.","authors":["IMB11","Tenneb22"],"files":[]},"headers":[],"relativePath":"ru_ru/1.21.10/develop/getting-started/launching-the-game.md","filePath":"versions/1.21.10/translated/ru_ru/develop/getting-started/launching-the-game.md","lastUpdated":1766682904000}`);var c={name:`ru_ru/1.21.10/develop/getting-started/launching-the-game.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Запуск игры <a class="header-anchor" href="#h1" aria-label="Permalink to “Запуск игры”">​</a></h1><p>Fabric Loom предоставляет различные профили запуска, которые помогут вам запускать и отлаживать моды в живой игровой среде. В данном руководстве мы рассмотрим различные профили запуска и то, как использовать их для отладки и тестирования ваших модов.</p><h2 id="launch-profiles" tabindex="-1">Профили запуска <a class="header-anchor" href="#launch-profiles" aria-label="Permalink to “Профили запуска”">​</a></h2><p>Если вы используете IntelliJ IDEA, вы можете найти профили запуска в правом верхнем углу окна. Нажмите на выпадающее меню, чтобы увидеть доступные профили запуска.</p><p>Должны быть доступны клиентский и серверный профили с возможностью запустить их в обычном или режиме отладки:</p><p><img src="/assets/develop/getting-started/launch-profiles.png" alt="Запуск профилей" loading="lazy"></p><h2 id="gradle-tasks" tabindex="-1">Задачи Gradle <a class="header-anchor" href="#gradle-tasks" aria-label="Permalink to “Задачи Gradle”">​</a></h2><p>Если вы используете командную строку, вы можете использовать следующие команды Gradle для запуска игры:</p><ul><li><code>./gradlew runClient</code> — запускает игру в клиентском режиме.</li><li><code>./gradlew runServer</code> — запускает игру в серверном режиме.</li></ul><p>Единственная проблема с этим подходом заключается в том, что вы не можете легко отлаживать свой код. Если вы хотите отлаживать код, вам нужно использовать профили запуска в IntelliJ IDEA или через интеграцию Gradle в вашей ИСР (IDE).</p><h2 id="hotswapping-classes" tabindex="-1">Горячая замена классов <a class="header-anchor" href="#hotswapping-classes" aria-label="Permalink to “Горячая замена классов”">​</a></h2><p>Когда вы запускаете игру в режиме отладки, вы можете делать горячую замену (hotswap) своих классов без перезапуска игры. Это полезно для быстрого тестирования изменений в коде.</p><p>Однако у этого есть ограничения:</p><ul><li>вы не можете добавлять или удалять методы,</li><li>вы не можете изменять параметры методов,</li><li>вы не можете добавлять или удалять поля.</li></ul><p>Однако, используя <a href="https://github.com/JetBrains/JetBrainsRuntime" target="_blank" rel="noreferrer">Runtime от JetBrains</a>, вы можете обойти большинство ограничений и даже добавлять или удалять классы и методы. Это позволит большинству изменений вступать в силу без перезапуска игры.</p><p>Не забудьте добавить следующее в опции VM Arguments в конфигурации запуска Minecraft:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>-XX:+AllowEnhancedClassRedefinition</span></span></code></pre></div><h2 id="hotswapping-mixins" tabindex="-1">Горячая замена миксинов <a class="header-anchor" href="#hotswapping-mixins" aria-label="Permalink to “Горячая замена миксинов”">​</a></h2><p>Если вы используете миксины, вы можете делать горячую замену классов миксинов без перезапуска игры. Это полезно для быстрого тестирования изменений в миксинах.</p><p>Однако для этого вам нужно установить Java-агент для миксинов.</p><h3 id="1-locate-the-mixin-library-jar" tabindex="-1">1. Найдите JAR-файл библиотеки Mixin <a class="header-anchor" href="#1-locate-the-mixin-library-jar" aria-label="Permalink to “1. Найдите JAR-файл библиотеки Mixin”">​</a></h3><p>В IntelliJ IDEA вы можете найти JAR-файл библиотеки Mixin в разделе External Libraries в разделе Project:</p><p><img src="/assets/develop/getting-started/mixin-library.png" alt="Библиотека Mixin" loading="lazy"></p><p>Вам нужно скопировать «абсолютный путь» (Absolute Path) этого JAR-файла для следующего шага.</p><h3 id="2-add-the--javaagent-vm-argument" tabindex="-1">2. Добавьте аргумент <code>-javaagent</code> в VM Arguments <a class="header-anchor" href="#2-add-the--javaagent-vm-argument" aria-label="Permalink to “2. Добавьте аргумент -javaagent в VM Arguments”">​</a></h3><p>В конфигурации запуска Minecraft Client и/или Minecraft Server добавьте следующее в опции VM Arguments:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>-javaagent:&quot;путь к JAR-файлу библиотеки Mixin&quot;</span></span></code></pre></div><p><img src="/assets/develop/getting-started/vm-arguments.png" alt="Скриншот VM Arguments" loading="lazy"></p><p>Теперь вы сможете изменять содержимое ваших Mixin-методов во время отладки, и изменения вступят в силу без перезапуска игры.</p>`,29)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};